    "content": "{"content":"}\nEXPORT_SYMBOL(dec_zone_page_state);\n\nvoid mod_node_page_state(struct pglist_data *pgdat, enum node_stat_item item,\n\t\t\t\t\tlong delta)\n{\n\tunsigned long flags;\n\n\tlocal_irq_save(flags);\n\t__mod_node_page_state(pgdat, item, delta);\n\tlocal_irq_restore(flags);\n}\nEXPORT_SYMBOL(mod_node_page_state);\n\nvoid inc_node_page_state(struct page *page, enum node_stat_item item)\n{\n\tunsigned long flags;\n\tstruct pglist_data *pgdat;\n\n\tpgdat = page_pgdat(page);\n\tlocal_irq_save(flags);\n\t__inc_node_state(pgdat, item);\n\tlocal_irq_restore(flags);\n}\nEXPORT_SYMBOL(inc_node_page_state);\n\nvoid dec_node_page_state(struct page *page, enum node_stat_item item)\n{\n\tunsigned long flags;\n\n\tlocal_irq_save(flags);\n\t__dec_node_page_state(page, item);\n\tlocal_irq_restore(flags);\n}\nEXPORT_SYMBOL(dec_node_page_state);\n#endif\n\n/*\n * Fold a differential into the global counters.\n * Returns whether counters were updated.\n */\nstatic int fold_diff(int *zone_diff, int *node_diff)\n{\n\tint i;\n\tbool changed = false;\n\n\tfor (i = 0; i < NR_VM_ZONE_STAT_ITEMS; i++) {\n\t\tif (zone_diff[i]) {\n\t\t\tatomic_long_add(zone_diff[i], &vm_zone_stat[i]);\n\t\t\tchanged = true;\n\t\t}\n\t}\n\n\tfor (i = 0; i < NR_VM_NODE_STAT_ITEMS; i++) {\n\t\tif (node_diff[i]) {\n\t\t\tatomic_long_add(node_diff[i], &vm_node_stat[i]);\n\t\t\tchanged = true;\n\t\t}\n\t}\n\n\treturn changed;\n}\n\n/*\n * Update the zone counters for the current cpu.\n *\n * Note that refresh_cpu_vm_stats strives to only access\n * node local memory. The per cpu pagesets on remote zones are placed\n * in the memory local to the processor using that pageset. So the\n * loop over all zones will access a series of cachelines local to\n * the processor.\n *\n * The call to zone_page_state_add updates the cachelines with the\n * statistics in the remote zone struct as well as the global cachelines\n * with the global counters. These could cause remote node cache line\n * bouncing and will have to be only done when necessary.\n *\n * The function returns whether global counters were updated.\n */\nstatic bool refresh_cpu_vm_stats(bool do_pagesets)\n{\n\tstruct pglist_data *pgdat;\n\tstruct zone *zone;\n\tint i;\n\tint global_zone_diff[NR_VM_ZONE_STAT_ITEMS] = { 0, };\n\tint global_node_diff[NR_VM_NODE_STAT_ITEMS] = { 0, };\n\tbool changed = false;\n\n\tfor_each_populated_zone(zone) {\n\t\tstruct per_cpu_zonestat __percpu *pzstats = zone->per_cpu_zonestats;\n\t\tstruct per_cpu_pages __percpu *pcp = zone->per_cpu_pageset;\n\n\t\tfor (i = 0; i < NR_VM_ZONE_STAT_ITEMS; i++) {\n\t\t\tint v;\n\n\t\t\tv = this_cpu_xchg(pzstats->vm_stat_diff[i], 0);\n\t\t\tif (v) {\n\n\t\t\t\tatomic_long_add(v, &zone->vm_stat[i]);\n\t\t\t\tglobal_zone_diff[i] += v;\n#ifdef CONFIG_NUMA\n\t\t\t\t/* 3 seconds idle till flush */\n\t\t\t\t__this_cpu_write(pcp->expire, 3);\n#endif\n\t\t\t}\n\t\t}\n\n\t\tif (do_pagesets) {\n\t\t\tcond_resched();\n\n\t\t\tif (decay_pcp_high(zone, this_cpu_ptr(pcp)))\n\t\t\t\tchanged = true;\n#ifdef CONFIG_NUMA\n\t\t\t/*\n\t\t\t * Deal with draining the remote pageset of this\n\t\t\t * processor\n\t\t\t *\n\t\t\t * Check if there are pages remaining in this pageset\n\t\t\t * if not then there is nothing to expire.\n\t\t\t */\n\t\t\tif (!__this_cpu_read(pcp->expire) ||\n\t\t\t       !__this_cpu_read(pcp->count))\n\t\t\t\tcontinue;\n\n\t\t\t/*\n\t\t\t * We never drain zones local to this processor.\n\t\t\t */\n\t\t\tif (zone_to_nid(zone) == numa_node_id()) {\n\t\t\t\t__this_cpu_write(pcp->expire, 0);\n\t\t\t\tcontinue;\n\t\t\t}\n\n\t\t\tif (__this_cpu_dec_return(pcp->expire)) {\n\t\t\t\tchanged = true;\n\t\t\t\tcontinue;\n\t\t\t}\n\n\t\t\tif (__this_cpu_read(pcp->count)) {\n\t\t\t\tdrain_zone_pages(zone, this_cpu_ptr(pcp));\n\t\t\t\tchanged = true;\n\t\t\t}\n#endif\n\t\t}\n\t}\n\n\tfor_each_online_pgdat(pgdat) {\n\t\tstruct per_cpu_nodestat __percpu *p = pgdat->per_cpu_nodestats;\n\n\t\tfor (i = 0; i < NR_VM_NODE_STAT_ITEMS; i++) {\n\t\t\tint v;\n\n\t\t\tv = this_cpu_xchg(p->vm_node_stat_diff[i], 0);\n\t\t\tif (v) {\n\t\t\t\tatomic_long_add(v, &pgdat->vm_stat[i]);\n\t\t\t\tglobal_node_diff[i] += v;\n\t\t\t}\n\t\t}\n\t}\n\n\tif (fold_diff(global_zone_diff, global_node_diff))\n\t\tchanged = true;\n\treturn changed;\n}\n\n/*\n * Fold the data for an offline cpu into the global array.\n * There cannot be any access by the offline cpu and therefore\n * synchronization is simplified.\n */\nvoid cpu_vm_stats_fold(int cpu)\n{\n\tstruct pglist_data *pgdat;\n\tstruct zone *zone;\n\tint i;\n\tint global_zone_diff[NR_VM_ZONE_STAT_ITEMS] = { 0, };\n\tint global_node_diff[NR_VM_NODE_STAT_ITEMS] = { 0, };\n\n\tfor_each_populated_zone(zone) {\n\t\tstruct per_cpu_zonestat *pzstats;\n\n\t\tpzstats = per_cpu_ptr(zone->per_cpu_zonestats, cpu);\n\n\t\tfor (i = 0; i < NR_VM_ZONE_STAT_ITEMS; i++) {\n\t\t\tif (pzstats->vm_stat_diff[i]) {\n\t\t\t\tint v;\n\n\t\t\t\tv = pzstats->vm_stat_diff[i];\n\t\t\t\tpzstats->vm_stat_diff[i] = 0;\n\t\t\t\tatomic_long_add(v, &zone->vm_stat[i]);\n\t\t\t\tglobal_zone_diff[i] += v;\n\t\t\t}\n\t\t}\n#ifdef CONFIG_NUMA\n\t\tfor (i = 0; i < NR_VM_NUMA_EVENT_ITEMS; i++) {\n\t\t\tif (pzstats->vm_numa_event[i]) {\n\t\t\t\tunsigned long v;\n\n\t\t\t\tv = pzstats->vm_numa_event[i];\n\t\t\t\tpzstats->vm_numa_event[i] = 0;\n\t\t\t\tzone_numa_event_add(v, zone, i);\n\t\t\t}\n\t\t}\n#endif\n\t}\n\n\tfor_each_online_pgdat(pgdat) {\n\t\tstruct per_cpu_nodestat *p;\n\n\t\tp = per_cpu_ptr(pgdat->per_cpu_nodestats, cpu);\n\n\t\tfor (i = 0; i < NR_VM_NODE_STAT_ITEMS; i++)\n\t\t\tif (p->vm_node_stat_diff[i]) {\n\t\t\t\tint v;\n\n\t\t\t\tv = p->vm_node_stat_diff[i];\n\t\t\t\tp->vm_node_stat_diff[i] = 0;\n\t\t\t\tatomic_long_add(v, &pgdat->vm_stat[i]);\n\t\t\t\tglobal_node_diff[i] += v;\n\t\t\t}\n\t}\n\n\tfold_diff(global_zone_diff, global_node_diff);\n}\n\n/*\n * this is only called if !populated_zone(zone), which implies no other users of\n * pset->vm_stat_diff[] exist.\n */\nvoid drain_zonestat(struct zone *zone, struct per_cpu_zonestat *pzstats)\n{\n\tunsigned long v;\n\tint i;\n\n\tfor (i = 0; i < NR_VM_ZONE_STAT_ITEMS; i++) {\n\t\tif (pzstats->vm_stat_diff[i]) {\n\t\t\tv = pzstats->vm_stat_diff[i];\n\t\t\tpzstats->vm_stat_diff[i] = 0;\n\t\t\tzone_page_state_add(v, zone, i);\n\t\t}\n\t}\n\n#ifdef CONFIG_NUMA\n\tfor (i = 0; i < NR_VM_NUMA_EVENT_ITEMS; i++) {\n\t\tif (pzstats->vm_numa_event[i]) {\n\t\t\tv = pzstats->vm_numa_event[i];\n\t\t\tpzstats->vm_numa_event[i] = 0;\n\t\t\tzone_numa_event_add(v, zone, i);\n\t\t}\n\t}\n#endif\n}\n#endif\n\n#ifdef CONFIG_NUMA\n/*\n * Determine the per node value of a stat item. This function\n * is called frequently in a NUMA machine, so try to be as\n * frugal as possible.\n */\nunsigned long sum_zone_node_page_state(int node,\n\t\t\t\t enum zone_stat_item item)\n{\n\tstruct zone *zones = NODE_DATA(node)->node_zones;\n\tint i;\n\tunsigned long count = 0;\n\n\tfor (i = 0; i < MAX_NR_ZONES; i++)\n\t\tcount += zone_page_state(zones + i, item);\n\n\treturn count;\n}\n\n/* Determine the per node value of a numa stat item. */\nunsigned long sum_zone_numa_event_state(int node,\n\t\t\t\t enum numa_stat_item item)\n{\n\tstruct zone *zones = NODE_DATA(node)->node_zones;\n\tunsigned long count = 0;\n\tint i;\n\n\tfor (i = 0; i < MAX_NR_ZONES; i++)\n\t\tcount += zone_numa_event_state(zones + i, item);\n\n\treturn count;\n}\n\n/*\n * Determine the per node value of a stat item.\n */\nunsigned long node_page_state_pages(struct pglist_data *pgdat,\n\t\t\t\t    enum node_stat_item item)\n{\n\tlong x = atomic_long_read(&pgdat->vm_stat[item]);\n#ifdef CONFIG_SMP\n\tif (x < 0)\n\t\tx = 0;\n#endif\n\treturn x;\n}\n\nunsigned long node_page_state(struct pglist_data *pgdat,\n\t\t\t      enum node_stat_item item)\n{\n\tVM_WARN_ON_ONCE(vmstat_item_in_bytes(item));\n\n\treturn node_page_state_pages(pgdat, item);\n}\n#endif\n\n/*\n * Count number of pages \"struct page\" and \"struct page_ext\" consume.\n * nr_memmap_boot_pages: # of pages allocated by boot allo